INSERT INTO `articles` (`id`, `title`, `slug`, `excerpt`, `content`, `featured_image`, `category`, `sport`, `author`, `is_premium`, `is_published`, `published_at`, `created_at`, `updated_at`, `expert_name`) VALUES (1, 'NBA Betting Consensus New York Knicks vs Utah Jazz', 'nba-betting-consensus-knicks-jazz', 'In the impending clash between the New York Knicks and Utah Jazz, the total over 228 points has garnered considerable attention, with an emphatic 85.7% backing from the betting public.', '<p>In the impending clash between the New York Knicks and Utah Jazz, the total over 228 points has garnered considerable attention, with an emphatic 85.7% backing from the betting public.</p><p>This overwhelming support indicates widespread anticipation for a high-scoring affair, potentially fueled by the offensive prowess of both teams.</p><p>The Inspin simulation model, which simulates every NBA game thousands of times, up over 150 units over the last three years. A $100 bettor of our NBA would have netted a profit of $15,000+ and, a $1,000 bettor would have won $150,000+.</p>', NULL, 'consensus', 'NBA', 'Sam Profeta', 0, 1, '2026-04-01 09:04:45', '2026-04-03 09:04:45', '2026-04-03 09:04:45', NULL);
INSERT INTO `articles` (`id`, `title`, `slug`, `excerpt`, `content`, `featured_image`, `category`, `sport`, `author`, `is_premium`, `is_published`, `published_at`, `created_at`, `updated_at`, `expert_name`) VALUES (2, 'NFL Week 13 Prime Time Public Betting Splits', 'nfl-week-13-prime-time-betting-splits', 'In Week 13 of the season, the two prime time games taking place are the Dallas Cowboys and Indianapolis Colts on Sunday Night Football.', '<p>In Week 13 of the season, the two prime time games taking place are the Dallas Cowboys and Indianapolis Colts on Sunday Night Football and the Tampa Bay Buccaneers and New Orleans Saints on Monday Night Football.</p><p>Looking at the splits for Sunday Night Football, the Cowboys are going into the game as 10.5-point favorites. On the spread, they are looking at a massive 93% of bets on them to cover and taking in 90% of the betting handle.</p>', NULL, 'trends', 'NFL', 'Sam Profeta', 0, 1, '2026-03-29 09:04:45', '2026-04-03 09:04:45', '2026-04-03 09:04:45', NULL);
INSERT INTO `articles` (`id`, `title`, `slug`, `excerpt`, `content`, `featured_image`, `category`, `sport`, `author`, `is_premium`, `is_published`, `published_at`, `created_at`, `updated_at`, `expert_name`) VALUES (3, 'NBA Betting Consensus Toronto Raptors vs Miami Heat', 'nba-betting-consensus-raptors-heat', 'The Miami Heat are 7.5-point favorites (-110) as they host the Toronto Raptors, with 62% of the betting public backing Miami to cover.', '<p>The Miami Heat are 7.5-point favorites (-110) as they host the Toronto Raptors, with 62% of the betting public backing Miami to cover. The Heat\'s strong home-court performance and balanced roster led by Jimmy Butler and Bam Adebayo make them a formidable opponent.</p><p>On the other side, Toronto, with their defensive grit and Pascal Siakam\'s leadership, aims to keep the game competitive.</p>', NULL, 'consensus', 'NBA', 'Sam Profeta', 1, 1, '2026-04-02 09:04:45', '2026-04-03 09:04:45', '2026-04-03 09:04:45', NULL);
INSERT INTO `articles` (`id`, `title`, `slug`, `excerpt`, `content`, `featured_image`, `category`, `sport`, `author`, `is_premium`, `is_published`, `published_at`, `created_at`, `updated_at`, `expert_name`) VALUES (4, 'MLB World Series Betting Preview', 'mlb-world-series-betting-preview', 'A comprehensive look at the World Series betting markets and where the smart money is going.', '<p>As the World Series approaches, bettors are analyzing every angle. From pitching matchups to historical trends, there are plenty of factors to consider when placing your bets on baseball\'s biggest stage.</p><p>Our simulation model has been tracking MLB performance metrics all season and we\'re ready to share our top picks.</p>', NULL, 'analysis', 'MLB', 'INSPIN Staff', 0, 1, '2026-03-31 09:04:45', '2026-04-03 09:04:45', '2026-04-03 09:04:45', NULL);
INSERT INTO `articles` (`id`, `title`, `slug`, `excerpt`, `content`, `featured_image`, `category`, `sport`, `author`, `is_premium`, `is_published`, `published_at`, `created_at`, `updated_at`, `expert_name`) VALUES (5, 'NHL Stanley Cup Playoff Betting Guide', 'nhl-stanley-cup-playoff-betting-guide', 'Everything you need to know about betting on the Stanley Cup Playoffs.', '<p>The Stanley Cup Playoffs offer some of the most exciting betting opportunities in sports. With best-of-seven series, there are multiple angles to approach your betting strategy.</p><p>Our expert handicappers have been tracking team performance, goaltending matchups, and home/away splits to bring you the best playoff picks.</p>', NULL, 'picks', 'NHL', 'INSPIN Staff', 1, 1, '2026-03-27 09:04:45', '2026-04-03 09:04:45', '2026-04-03 09:04:45', NULL);
