-- ----------------------------------------
-- Table: betting_consensuses
-- ----------------------------------------
DROP TABLE IF EXISTS `betting_consensuses`;
CREATE TABLE `betting_consensuses` (`id` INT NOT NULL AUTO_INCREMENT PRIMARY KEY, `sport` VARCHAR(255) NOT NULL, `league` VARCHAR(255) NOT NULL, `home_team` VARCHAR(255) NOT NULL, `away_team` VARCHAR(255) NOT NULL, `game_DATE` DATETIME NOT NULL, `moneyline_home` VARCHAR(255), `moneyline_away` VARCHAR(255), `spread_home` VARCHAR(255), `spread_away` VARCHAR(255), `total_over` VARCHAR(255), `total_under` VARCHAR(255), `public_pct_home` DECIMAL(10,2) NOT NULL DEFAULT '50', `public_pct_away` DECIMAL(10,2) NOT NULL DEFAULT '50', `money_pct_home` DECIMAL(10,2), `money_pct_away` DECIMAL(10,2), `venue` VARCHAR(255), `broadcast` VARCHAR(255), `created_at` DATETIME, `updated_at` DATETIME)
ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;


-- ----------------------------------------
-- Table: contests
-- ----------------------------------------
DROP TABLE IF EXISTS `contests`;
CREATE TABLE `contests` (`id` INT NOT NULL AUTO_INCREMENT PRIMARY KEY, `name` VARCHAR(255) NOT NULL, `contest_type` VARCHAR(255), `description` TEXT, `starts_at` DATE, `ends_at` DATE, `status` VARCHAR(255) NOT NULL DEFAULT 'draft', `created_at` DATETIME, `updated_at` DATETIME)
ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;


-- ----------------------------------------
-- Table: experts
-- ----------------------------------------
DROP TABLE IF EXISTS `experts`;
CREATE TABLE `experts` (`id` INT NOT NULL AUTO_INCREMENT PRIMARY KEY, `name` VARCHAR(255) NOT NULL, `slug` VARCHAR(255) NOT NULL, `bio` TEXT, `avatar` VARCHAR(255), `specialty` VARCHAR(255), `is_active` TINYINT(1) NOT NULL DEFAULT '1', `created_at` DATETIME, `updated_at` DATETIME)
ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;


-- ----------------------------------------
-- Table: failed_jobs
-- ----------------------------------------
DROP TABLE IF EXISTS `failed_jobs`;
CREATE TABLE `failed_jobs` (`id` INT NOT NULL AUTO_INCREMENT PRIMARY KEY, `uuid` VARCHAR(255) NOT NULL, `connection` TEXT NOT NULL, `queue` TEXT NOT NULL, `payload` TEXT NOT NULL, `exception` TEXT NOT NULL, `failed_at` DATETIME DEFAULT CURRENT_TIMESTAMP NOT NULL)
ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

-- ----------------------------------------
-- Table: migrations
-- ----------------------------------------
DROP TABLE IF EXISTS `migrations`;
CREATE TABLE `migrations` (`id` INT NOT NULL AUTO_INCREMENT PRIMARY KEY, `migration` VARCHAR(255) NOT NULL, `batch` INT NOT NULL)
ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;


-- ----------------------------------------
-- Table: packages
-- ----------------------------------------
DROP TABLE IF EXISTS `packages`;
CREATE TABLE `packages` (`id` INT NOT NULL AUTO_INCREMENT PRIMARY KEY, `name` VARCHAR(255) NOT NULL, `slug` VARCHAR(255) NOT NULL, `description` TEXT, `price` DECIMAL(10,2) NOT NULL, `duration` VARCHAR(255) NOT NULL, `duration_days` INT NOT NULL, `features` TEXT, `is_active` TINYINT(1) NOT NULL DEFAULT '1', `sort_order` INT NOT NULL DEFAULT '0', `created_at` DATETIME, `updated_at` DATETIME)
ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;


-- ----------------------------------------
-- Table: password_resets
-- ----------------------------------------
DROP TABLE IF EXISTS `password_resets`;
CREATE TABLE `password_resets` (`email` VARCHAR(255) NOT NULL, `token` VARCHAR(255) NOT NULL, `created_at` DATETIME)
ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

-- ----------------------------------------
-- Table: personal_access_tokens
-- ----------------------------------------
DROP TABLE IF EXISTS `personal_access_tokens`;
CREATE TABLE `personal_access_tokens` (`id` INT NOT NULL AUTO_INCREMENT PRIMARY KEY, `tokenable_type` VARCHAR(255) NOT NULL, `tokenable_id` INT NOT NULL, `name` VARCHAR(255) NOT NULL, `token` VARCHAR(255) NOT NULL, `abilities` TEXT, `last_used_at` DATETIME, `created_at` DATETIME, `updated_at` DATETIME)
ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

-- ----------------------------------------
-- Table: picks
-- ----------------------------------------
DROP TABLE IF EXISTS `picks`;
CREATE TABLE `picks` (`id` INT NOT NULL AUTO_INCREMENT PRIMARY KEY, `sport` VARCHAR(255), `game_DATE` DATE, `game_TIME` TIME, `team1_name` VARCHAR(255), `team1_logo` VARCHAR(255), `team1_rotation` INT, `team2_name` VARCHAR(255), `team2_logo` VARCHAR(255), `team2_rotation` INT, `venue` VARCHAR(255), `pick` VARCHAR(255), `simulation_result` VARCHAR(255), `stars` INT NOT NULL DEFAULT '1', `result` varchar check (`result` in ('pending', 'win', 'loss', 'push')) NOT NULL DEFAULT 'pending', `units` DECIMAL(10,2), `expert_name` VARCHAR(255), `related_article_id` VARCHAR(255), `is_active` TINYINT(1) NOT NULL DEFAULT '1', `is_whale_exclusive` TINYINT(1) NOT NULL DEFAULT '0', `created_at` DATETIME, `updated_at` DATETIME)
ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;


-- ----------------------------------------
-- Table: support_tickets
-- ----------------------------------------
DROP TABLE IF EXISTS `support_tickets`;
CREATE TABLE `support_tickets` (`id` INT NOT NULL AUTO_INCREMENT PRIMARY KEY, `source_system` VARCHAR(255) NOT NULL DEFAULT 'legacy', `external_id` VARCHAR(255), `customer_name` VARCHAR(255), `customer_email` VARCHAR(255), `subject` VARCHAR(255), `message` TEXT, `status` VARCHAR(255) NOT NULL DEFAULT 'open', `priority` VARCHAR(255), `legacy_created_at` DATETIME, `legacy_updated_at` DATETIME, `created_at` DATETIME, `updated_at` DATETIME)
ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;


-- ----------------------------------------
-- Table: team_logos
-- ----------------------------------------
DROP TABLE IF EXISTS `team_logos`;
CREATE TABLE `team_logos` (`id` INT NOT NULL AUTO_INCREMENT PRIMARY KEY, `team_name` VARCHAR(255) NOT NULL, `sport` VARCHAR(255) NOT NULL, `logo_path` VARCHAR(255), `abbreviation` VARCHAR(255), `is_active` TINYINT(1) NOT NULL DEFAULT '1', `created_at` DATETIME, `updated_at` DATETIME)
ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;


-- ----------------------------------------
-- Table: tips
-- ----------------------------------------
DROP TABLE IF EXISTS `tips`;
CREATE TABLE `tips` (`id` INT NOT NULL AUTO_INCREMENT PRIMARY KEY, `added_DATE` DATE, `tip_title` VARCHAR(255), `tip_TEXT` TEXT, `group_name` VARCHAR(255), `display_yearly` TINYINT(1) NOT NULL DEFAULT '0', `display_DATE` DATE, `shown_DATE` DATE, `display_day` INT, `created_at` DATETIME, `updated_at` DATETIME, `is_active` TINYINT(1) NOT NULL DEFAULT '1', `expert_name` VARCHAR(255), `matchup` VARCHAR(255), `confidence` INT, `result` VARCHAR(255), `analysis` TEXT)
ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;


-- ----------------------------------------
-- Table: user_packages
-- ----------------------------------------
DROP TABLE IF EXISTS `user_packages`;
CREATE TABLE `user_packages` (`id` INT NOT NULL AUTO_INCREMENT PRIMARY KEY, `user_id` INT NOT NULL, `package_id` INT NOT NULL, `starts_at` DATETIME NOT NULL, `expires_at` DATETIME NOT NULL, `is_active` TINYINT(1) NOT NULL DEFAULT '1', `created_at` DATETIME, `updated_at` DATETIME, foreign key(`user_id`) references `users`(`id`) on delete cascade, foreign key(`package_id`) references `packages`(`id`) on delete cascade)
ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

-- ----------------------------------------
-- Table: users
-- ----------------------------------------
DROP TABLE IF EXISTS `users`;
CREATE TABLE `users` (`id` INT NOT NULL AUTO_INCREMENT PRIMARY KEY, `name` VARCHAR(255) NOT NULL, `email` VARCHAR(255) NOT NULL, `email_verified_at` DATETIME, `password` VARCHAR(255) NOT NULL, `remember_token` VARCHAR(255), `created_at` DATETIME, `updated_at` DATETIME, `phone` VARCHAR(255), `role` VARCHAR(255) NOT NULL DEFAULT 'free')
ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;


-- ----------------------------------------
-- Table: whale_packages
-- ----------------------------------------
DROP TABLE IF EXISTS `whale_packages`;
CREATE TABLE `whale_packages` (`id` INT NOT NULL AUTO_INCREMENT PRIMARY KEY, `title` VARCHAR(255) NOT NULL, `description` TEXT, `price` DECIMAL(10,2) NOT NULL, `duration` VARCHAR(255) NOT NULL DEFAULT 'Custom', `duration_days` INT NOT NULL DEFAULT '30', `features` TEXT, `banner_image` VARCHAR(255), `is_active` TINYINT(1) NOT NULL DEFAULT '1', `sort_order` INT NOT NULL DEFAULT '0', `created_at` DATETIME, `updated_at` DATETIME)
ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;



